using System;
using System.Data.SqlClient;
using System.Threading.Tasks;

public class DatabaseHelper
{
    private static readonly string ConnectionString = "Server=localhost;Database=HackathonDB;User Id=sa;Password=DevPass123!;";

    public static async Task<SqlConnection> GetConnectionAsync()
    {
        var connection = new SqlConnection(ConnectionString);
        await connection.OpenAsync();
        return connection;
    }

    public static async Task<T> ExecuteQueryAsync<T>(Func<SqlConnection, Task<T>> query)
    {
        using var connection = await GetConnectionAsync();
        return await query(connection);
    }

    public static async Task ExecuteNonQueryAsync(string sql, params SqlParameter[] parameters)
    {
        await ExecuteQueryAsync(async connection =>
        {
            using var command = new SqlCommand(sql, connection);
            command.Parameters.AddRange(parameters);
            await command.ExecuteNonQueryAsync();
            return 0;
        });
    }

    public static async Task<T> ExecuteScalarAsync<T>(string sql, params SqlParameter[] parameters)
    {
        return await ExecuteQueryAsync(async connection =>
        {
            using var command = new SqlCommand(sql, connection);
            command.Parameters.AddRange(parameters);
            var result = await command.ExecuteScalarAsync();
            return result != null ? (T)Convert.ChangeType(result, typeof(T)) : default(T);
        });
    }

    public static async Task<SqlDataReader> ExecuteReaderAsync(string sql, params SqlParameter[] parameters)
    {
        return await ExecuteQueryAsync(async connection =>
        {
            var command = new SqlCommand(sql, connection);
            command.Parameters.AddRange(parameters);
            return await command.ExecuteReaderAsync();
        });
    }
}